4	\chapter{Algebraic Iwasawa Comparison}
5	\label{chap:algebraic-comparison}
6	
7	% archon:covers MR4372220OnTheAnticyclotomicIwasawaTheoryOfRationalEllipticCurvesAtEisensteinPrimes/Algebraic.lean
8	
9	This chapter isolates the algebraic comparison lane. The local Selmer formalism is taken as given: here we only compare the residual decomposition
10	\[
11	E[p]^{ss}\cong \mathbb F_p(\phi)\oplus \mathbb F_p(\psi)
12	\]
13	with the corresponding character Selmer groups, and we record the local Euler-factor bookkeeping that produces the \(\lambda\)-formula for \(\mathfrak X_E\).
14	
15	Throughout, we write
16	\[
17	\mathfrak X_E^S:=\rH^1_{\Fcal_{\rm Gr}^S}(K,M_E)^\vee,
18	\qquad
19	\mathfrak X_E:=\rH^1_{\Fcal_{\rm Gr}}(K,M_E)^\vee,
20	\]
21	and for each split prime \(w\nmid p\) in \(S\) we use
22	\[
23	\mathcal P_w(E)=P_w(\ell^{-1}\gamma_w)\in\Lambda
24	\]
25	for the local Euler factor of \(E\). The character-side modules and Euler factors are supplied by the local Selmer chapter.
26	
27	\section{Residual comparison}
28	
29	\begin{proposition}[Residual comparison for \(E[p]\)]
30	  \label{prop:modp-E}
31	  \lean{MR4372220.Algebraic.residualComparison}
32	  \uses{def:iwasawa-algebra, cor:characters}
33	  % SOURCE: [MR4372220], Prop.~\ref{cormodp}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
34	  % SOURCE QUOTE: "0 \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \rightarrow"
35	  \textit{Source: MR4372220, Selmer groups of E.}
36	  The short exact sequence \(0 \to M_\phi[p] \to M_E[p] \to M_\psi[p] \to 0\) induces a natural exact sequence
37	  \[
38	  0 \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \to
39	  \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\psi[p]) \to 0.
40	  \]
41	  In particular, the imprimitive residual Selmer group of \(E\) is finite, and its \(\mathbb F_p\)-dimension is the sum of the corresponding character dimensions.
42	\end{proposition}
43	
44	\begin{proof}
45	The restriction diagram at \(\bar v\) has exact rows for \(\phi\), \(\psi\), and \(E\). Applying the snake lemma gives the exact sequence on \(S\)-imprimitive residual Selmer groups. The finiteness and dimension statement follows by adding the character-side residual dimensions.
46	\end{proof}
47	
48	\begin{proposition}[Torsion and \(\mu=0\) for \(E\)]
49	  \label{prop:modp-E-tors}
50	  \lean{MR4372220.Algebraic.muZeroE}
51	  \uses{prop:modp-E}
52	  % SOURCE: [MR4372220], Prop.~\ref{propmodp}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
53	  % SOURCE QUOTE: "the modules \mathfrak{X}_E^S and \mathfrak{X}_E are both \Lambda-torsion with \mu=0"
54	  \textit{Source: MR4372220, Selmer groups of E.}
55	  The natural map
56	  \[
57	  \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \simeq \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E)[p]
58	  \]
59	  identifies the residual and \(p\)-torsion Selmer groups. Consequently, \(\mathfrak X_E^S\) and \(\mathfrak X_E\) are \(\Lambda\)-torsion, and both have \(\mu\)-invariant zero.
60	\end{proposition}
61	
62	\begin{proof}
63	The assumption on \(\phi|_{G_p}\) forces \(E(K_{\bar v})[p]=0\), so the local \(p\)-torsion comparison at \(\bar v\) is an isomorphism. The finiteness of the residual group then implies \(\mu=0\) for \(\mathfrak X_E^S\), and the quotient map \(\mathfrak X_E^S \twoheadrightarrow \mathfrak X_E\) gives the same conclusion for \(\mathfrak X_E\).
64	\end{proof}
65	
66	\begin{corollary}[No finite submodules]
67	  \label{cor:lambda-E}
68	  \lean{MR4372220.Algebraic.lambdaE}
69	  \uses{prop:modp-E-tors, lem:local-char-wp}
70	  % SOURCE: [MR4372220], Cor.~\ref{prop426}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
71	  % SOURCE QUOTE: "\mathfrak{X}_E^S has no non-trivial finite \Lambda-submodules"
72	  \textit{Source: MR4372220, Selmer groups of E.}
73	  The module \(\mathfrak X_E^S\) has no non-trivial finite \(\Lambda\)-submodules, and
74	  \[
75	  \lambda(\mathfrak X_E^S)=\dim_{\mathbb F_p}\rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]).
76	  \]
77	\end{corollary}
78	
79	\begin{proof}
80	The dual local cohomology at \(\bar v\) is \(\Lambda\)-cofree, so the standard Greenberg quotient argument removes finite submodules. Combined with the identification of residual and \(p\)-torsion Selmer groups from the previous proposition, this gives the \(\lambda\)-dimension formula.
81	\end{proof}
82	
83	\section{Algebraic comparison theorem}
84	
85	\begin{theorem}[Algebraic Iwasawa comparison]
86	  \label{MAINalgside}
87	  \lean{MR4372220.Algebraic.mainAlgSide}
88	  \uses{prop:modp-E-tors, cor:lambda-E, prop:lambda-theta}
89	  % SOURCE: [MR4372220], Thm.~\ref{MAINalgside}, §Algebraic side, Comparison I: Algebraic Iwasawa invariants (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
90	  % SOURCE QUOTE: "\mathfrak{X}_E is \Lambda-torsion with \mu(\mathfrak{X}_E)=0"
91	  \textit{Source: MR4372220, Comparison I: Algebraic Iwasawa invariants.}
92	  Assume that \(\phi|_{G_p}\neq \mathds{1},\omega\). Then \(\mathfrak X_E\) is \(\Lambda\)-torsion with \(\mu(\mathfrak X_E)=0\), and
93	  \[
94	  \lambda(\mathfrak X_E)=\lambda(\mathfrak X_\phi)+\lambda(\mathfrak X_\psi)
95	  +\sum_{w\in S}\Bigl(\lambda(\mathcal P_w(\phi))+\lambda(\mathcal P_w(\psi))-\lambda(\mathcal P_w(E))\Bigr).
96	  \]
97	\end{theorem}
98	
99	\begin{proof}
100	The torsion and \(\mu\)-vanishing part is already supplied by Proposition~\ref{prop:modp-E-tors}. For the \(\lambda\)-invariant, the corollary gives the residual comparison on the \(E\)-side, while the character-side formula supplies the corresponding identity for \(\mathfrak X_\phi\) and \(\mathfrak X_\psi\). The only remaining step is to subtract the local split-prime Euler factors, whose \(E\)-contribution is \(\mathcal P_w(E)\) and whose character contributions are \(\mathcal P_w(\phi)\) and \(\mathcal P_w(\psi)\).
101	\end{proof}
