5	\chapter{Analytic Iwasawa Comparison}
6	\label{chap:analytic-comparison}
7	
8	% archon:covers MR4372220OnTheAnticyclotomicIwasawaTheoryOfRationalEllipticCurvesAtEisensteinPrimes/Analytic.lean
9	
10	Throughout this chapter, \(E/\mathbb{Q}\) is an elliptic curve of conductor \(N\), \(p\nmid 2N\) is a prime of good reduction for \(E\), and \(K\) is an imaginary quadratic field satisfying the Heegner, split, and discriminant hypotheses of Castella--Grossi--Lee--Skinner: in particular \(p = v\bar{v}\) splits in \(K\). We assume \(E[p]^{ss} \simeq \mathbb{F}_p(\phi)\oplus\mathbb{F}_p(\psi)\) as \(G_{\mathbb{Q}}\)-modules, with \(\phi,\psi\) labeled so that \(p\nmid\mathrm{cond}(\phi)\) and \(\phi\neq\mathds{1}\). We fix an integral ideal \(\mathfrak{N}\subset\mathcal{O}_K\) with \(\mathcal{O}_K/\mathfrak{N}\simeq\mathbb{Z}/N\mathbb{Z}\). The Iwasawa algebra \(\Lambda\) and the modules \(M_\theta\), \(M_E\), and the Euler factors \(\mathcal{P}_w(\cdot)\) are as in \cref{def:iwasawa-algebra}.
11	
12	\section{\texorpdfstring{\(p\)}{p}-adic \texorpdfstring{\(L\)}{L}-functions}
13	
14	\subsection{The Bertolini--Darmon--Prasanna \texorpdfstring{\(p\)}{p}-adic \texorpdfstring{\(L\)}{L}-function}
15	
16	\begin{theorem}[BDP anticyclotomic \(p\)-adic \(L\)-function]
17	  \label{thm:BDP}
18	  \lean{MR4372220.Analytic.bdpLFunction}
19	  \uses{def:iwasawa-algebra}
20	  % SOURCE: [Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, p-adic L-functions, Thm.~\ref{thm:BDP}] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
21	  % SOURCE QUOTE: "There exists an element $\Lcal_E\in\Lambda^{\rm ur}$ characterized by the following interpolation property: For every character $\xi$ of $\Gamma$ crystalline at both $v$ and $\bar{v}$ and corresponding to a Hecke character of $K$ of infinity type $(n,-n)$ with $n\in\Z_{>0}$ and $n\equiv 0\pmod{p-1}$, we have $\mathcal{L}_E(\xi)=\frac{\Omega_p^{4n}}{\Omega_\infty^{4n}}\cdot\frac{\Gamma(n)\Gamma(n+1)\xi(\mathfrak{N}^{-1})}{4(2\pi)^{2n+1}\sqrt{D_K}^{2n-1}}\cdot\bigl(1-a_p\xi(\bar{v})p^{-1}+\xi(\bar{v})^2p^{-1}\bigr)^2\cdot L(f/K,\xi,1)$, where $\Omega_p$ and $\Omega_\infty$ are CM periods attached to $K$ as in \cite[\S{2.5}]{cas-hsieh1}."
22	  \textit{Source: Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, \S{}\(p\)-adic \(L\)-functions, Theorem~BDP.}
23	
24	  There exists an element \(\Lcal_E \in \Lambda^{\mathrm{ur}}\) characterized by the following interpolation property. For every character \(\xi\) of \(\Gamma\) crystalline at both \(v\) and \(\bar{v}\) and corresponding to a Hecke character of \(K\) of infinity type \((n,-n)\) with \(n\in\mathbb{Z}_{>0}\) and \(n\equiv 0\pmod{p-1}\), we have
25	  \[
26	    \Lcal_E(\xi)
27	    = \frac{\Omega_p^{4n}}{\Omega_\infty^{4n}}
28	      \cdot\frac{\Gamma(n)\Gamma(n+1)\,\xi(\mathfrak{N}^{-1})}{4\,(2\pi)^{2n+1}\sqrt{D_K}^{2n-1}}
29	      \cdot\bigl(1 - a_p\xi(\bar{v})p^{-1} + \xi(\bar{v})^2 p^{-1}\bigr)^2
30	      \cdot L(f/K,\xi,1),
31	  \]
32	  where \(\Omega_p\) and \(\Omega_\infty\) are the CM periods attached to \(K\), \(f\in S_2(\Gamma_0(N))\) is the newform associated with \(E\), and the Euler factor \(\bigl(1-a_p\xi(\bar{v})p^{-1}+\xi(\bar{v})^2p^{-1}\bigr)^2\) is nonzero under our hypotheses.
33	\end{theorem}
34	
35	% SOURCE QUOTE PROOF: "This was originally constructed in \cite{BDP} as a continuous function of $\xi$, and later explicitly constructed as a measure in \cite{cas-hsieh1} (following the approach in \cite{brakocevic}). Since this refined construction will be important for our purposes in this section, we recall some of the details."
36	\begin{proof}
